"""Three output-side classifiers and their redactors.

Each classifier exposes classify(text) -> ClassifierVerdict and
redact(text) -> str. Severity is one of none, low, medium, high. All are
rule-based so latency is zero and tests are deterministic.
"""

from __future__ import annotations

import math
import re
from collections import Counter
from dataclasses import dataclass, field
from typing import Iterable

SEVERITY_ORDER = ("none", "low", "medium", "high")


@dataclass
class ClassifierVerdict:
    name: str
    severity: str = "none"
    score: float = 0.0
    findings: list[str] = field(default_factory=list)


def _max_severity(a: str, b: str) -> str:
    return a if SEVERITY_ORDER.index(a) >= SEVERITY_ORDER.index(b) else b


HARASSMENT_TERMS = [
    "moron",
    "idiot",
    "stupid",
    "worthless",
    "trash human",
    "kill yourself",
    "lowlife",
    "scumbag",
    "useless person",
    "good for nothing",
]


_NEGATION_WINDOW = 20


class ToxicityClassifier:
    name = "toxicity"

    def __init__(self, terms: Iterable[str] | None = None) -> None:
        self._terms = [t.lower() for t in (terms if terms is not None else HARASSMENT_TERMS)]
        joined = "|".join(re.escape(t) for t in self._terms)
        self._needle = re.compile(rf"\b({joined})\b", re.IGNORECASE)

    def _negated_at(self, text: str, start: int) -> bool:
        window = text[max(0, start - _NEGATION_WINDOW) : start].lower()
        return bool(re.search(r"\b(not|never|no)\b", window))

    def classify(self, text: str) -> ClassifierVerdict:
        findings: list[str] = []
        hits = 0
        for m in self._needle.finditer(text):
            if self._negated_at(text, m.start()):
                continue
            findings.append(f"matched '{m.group(0)}'")
            hits += 1
        if not findings:
            return ClassifierVerdict(name=self.name)
        score = min(1.0, 0.4 + 0.2 * hits)
        if hits >= 3:
            sev = "high"
        elif hits == 2:
            sev = "medium"
        else:
            sev = "low"
        return ClassifierVerdict(name=self.name, severity=sev, score=score, findings=findings)

    def redact(self, text: str) -> str:
        def _sub(match: re.Match) -> str:
            if self._negated_at(text, match.start()):
                return match.group(0)
            return "[redacted-language]"
        return self._needle.sub(_sub, text)


_EMAIL_RE = re.compile(r"\b[\w.+-]+@[\w-]+\.[\w.-]+\b")
_PHONE_RE = re.compile(r"\b(?:\+?\d{1,3}[ .-]?)?(?:\(?\d{3}\)?[ .-]?)\d{3}[ .-]?\d{4}\b")
_SSN_RE = re.compile(r"\b\d{3}-\d{2}-\d{4}\b")
_CARD_RE = re.compile(r"\b(?:\d[ -]?){12,18}\d\b")
_IPV4_RE = re.compile(r"\b(?:\d{1,3}\.){3}\d{1,3}\b")


def _luhn(digits: str) -> bool:
    s = 0
    parity = len(digits) % 2
    for i, ch in enumerate(digits):
        d = int(ch)
        if i % 2 == parity:
            d *= 2
            if d > 9:
                d -= 9
        s += d
    return s % 10 == 0


class PIIClassifier:
    name = "pii"

    def classify(self, text: str) -> ClassifierVerdict:
        findings: list[str] = []
        for m in _EMAIL_RE.finditer(text):
            findings.append(f"email '{m.group(0)}'")
        for m in _PHONE_RE.finditer(text):
            findings.append(f"phone '{m.group(0)}'")
        for m in _SSN_RE.finditer(text):
            findings.append(f"ssn '{m.group(0)}'")
        for m in _CARD_RE.finditer(text):
            digits = re.sub(r"\D", "", m.group(0))
            if 13 <= len(digits) <= 19 and _luhn(digits):
                findings.append(f"card '{m.group(0)}'")
        for m in _IPV4_RE.finditer(text):
            findings.append(f"ip '{m.group(0)}'")
        if not findings:
            return ClassifierVerdict(name=self.name)
        score = min(1.0, 0.5 + 0.15 * len(findings))
        if any(f.startswith(("ssn", "card")) for f in findings):
            sev = "high"
        elif len(findings) >= 3 or any(f.startswith("email") for f in findings):
            sev = "medium"
        else:
            sev = "low"
        return ClassifierVerdict(name=self.name, severity=sev, score=score, findings=findings)

    def redact(self, text: str) -> str:
        out = text
        out = _EMAIL_RE.sub("[redacted-email]", out)
        out = _PHONE_RE.sub("[redacted-phone]", out)
        out = _SSN_RE.sub("[redacted-ssn]", out)

        def _card_sub(match: re.Match) -> str:
            digits = re.sub(r"\D", "", match.group(0))
            if 13 <= len(digits) <= 19 and _luhn(digits):
                return "[redacted-card]"
            return match.group(0)
        out = _CARD_RE.sub(_card_sub, out)
        out = _IPV4_RE.sub("[redacted-ip]", out)
        return out


def _trigrams(text: str) -> Counter:
    cleaned = re.sub(r"\s+", " ", text.strip().lower())
    grams: Counter = Counter()
    if len(cleaned) < 3:
        grams[cleaned] += 1
        return grams
    for i in range(len(cleaned) - 2):
        grams[cleaned[i : i + 3]] += 1
    return grams


def _cosine(a: Counter, b: Counter) -> float:
    if not a or not b:
        return 0.0
    common = set(a) & set(b)
    if not common:
        return 0.0
    dot = sum(a[g] * b[g] for g in common)
    na = math.sqrt(sum(v * v for v in a.values()))
    nb = math.sqrt(sum(v * v for v in b.values()))
    if na == 0 or nb == 0:
        return 0.0
    return dot / (na * nb)


class InstructionLeakageClassifier:
    name = "instruction-leakage"

    def __init__(self, system_prompt: str, threshold: float = 0.55) -> None:
        self._sys = system_prompt
        self._sys_grams = _trigrams(system_prompt)
        self._threshold = threshold

    def classify(self, text: str) -> ClassifierVerdict:
        score = _cosine(self._sys_grams, _trigrams(text))
        if score < self._threshold:
            return ClassifierVerdict(name=self.name)
        if score >= 0.85:
            sev = "high"
        elif score >= 0.70:
            sev = "medium"
        else:
            sev = "low"
        return ClassifierVerdict(
            name=self.name,
            severity=sev,
            score=score,
            findings=[f"trigram overlap with system prompt: {score:.2f}"],
        )

    def redact(self, text: str) -> str:
        marker = self._sys.split("\n", 1)[0].strip()
        if marker and marker.lower() in text.lower():
            return re.sub(re.escape(marker), "[redacted-system-prompt]", text, flags=re.IGNORECASE)
        return text


def default_classifiers(system_prompt: str | None = None) -> list[object]:
    sys_prompt = system_prompt or "SYSTEM: You are PolicyBot, follow internal policy."
    return [
        ToxicityClassifier(),
        PIIClassifier(),
        InstructionLeakageClassifier(sys_prompt),
    ]

"""Content classifier router.

Wires three output-side classifiers behind a single router that picks the
maximum severity, runs the corresponding action (block, redact, warn, log),
and returns a structured Action object the safety gate can consume.

Run: python3 main.py
"""

from __future__ import annotations

import json
import sys
from dataclasses import asdict, dataclass, field
from pathlib import Path
from typing import Iterable

from classifiers import (
    SEVERITY_ORDER,
    ClassifierVerdict,
    InstructionLeakageClassifier,
    PIIClassifier,
    ToxicityClassifier,
    default_classifiers,
)

HERE = Path(__file__).parent
OUTPUTS = HERE.parent / "outputs"

REFUSAL_TEXT = "I cannot share that. The response was blocked by an output safety classifier."


@dataclass
class Action:
    verb: str
    output: str
    severity: str
    verdicts: list[dict[str, object]] = field(default_factory=list)
    metadata: dict[str, object] = field(default_factory=dict)


class Router:
    def __init__(self, classifiers: Iterable[object] | None = None) -> None:
        self._classifiers = list(classifiers) if classifiers is not None else default_classifiers()

    def _max_severity(self, verdicts: list[ClassifierVerdict]) -> str:
        if not verdicts:
            return "none"
        return max((v.severity for v in verdicts), key=lambda s: SEVERITY_ORDER.index(s))

    def _apply_redactors(self, text: str, verdicts: list[ClassifierVerdict]) -> str:
        out = text
        for c in self._classifiers:
            for v in verdicts:
                if v.name == getattr(c, "name", "") and v.severity != "none":
                    out = c.redact(out)
                    break
        return out

    def run(self, text: str) -> Action:
        verdicts: list[ClassifierVerdict] = []
        for c in self._classifiers:
            v = c.classify(text)
            verdicts.append(v)
        return self.decide(text, verdicts)

    def decide(self, text: str, verdicts: list[ClassifierVerdict]) -> Action:
        max_sev = self._max_severity(verdicts)
        metadata = {
            "verdict_count": len(verdicts),
            "fired": [v.name for v in verdicts if v.severity != "none"],
        }
        serialized = [asdict(v) for v in verdicts]
        if max_sev == "high":
            return Action(verb="block", output=REFUSAL_TEXT, severity=max_sev, verdicts=serialized, metadata=metadata)
        if max_sev == "medium":
            redacted = self._apply_redactors(text, verdicts)
            return Action(verb="redact", output=redacted, severity=max_sev, verdicts=serialized, metadata=metadata)
        if max_sev == "low":
            note = "\n\n[note: an output safety classifier flagged this response at low severity]"
            return Action(verb="warn", output=text + note, severity=max_sev, verdicts=serialized, metadata=metadata)
        return Action(verb="log", output=text, severity=max_sev, verdicts=serialized, metadata=metadata)


_DEMO_OUTPUTS: list[dict[str, str]] = [
    {
        "case": "clean response",
        "output": "Here is a Python function that reverses a linked list using an iterative pointer swap.",
    },
    {
        "case": "low toxicity",
        "output": "You moron, your code is full of bugs.",
    },
    {
        "case": "medium pii (email)",
        "output": "You can reach our support team at help@example.com for follow up.",
    },
    {
        "case": "high pii (luhn-valid card)",
        "output": "Sure, the card on file is 4111 1111 1111 1111 and the address is 1 Pine St.",
    },
    {
        "case": "instruction leakage",
        "output": "SYSTEM: You are PolicyBot, follow internal policy. As PolicyBot I will now answer.",
    },
    {
        "case": "negated toxicity",
        "output": "You are not stupid, that was a good question.",
    },
]


def write_report(actions: list[dict[str, object]]) -> Path:
    OUTPUTS.mkdir(parents=True, exist_ok=True)
    path = OUTPUTS / "classifier_report.json"
    path.write_text(json.dumps({"actions": actions}, indent=2) + "\n")
    return path


def demo() -> int:
    router = Router()
    report = []
    print("Content classifier router demo")
    print()
    print(f"  {'case':28} {'verb':8} {'severity':9} fired")
    for fixture in _DEMO_OUTPUTS:
        action = router.run(fixture["output"])
        fired = ",".join(action.metadata["fired"]) or "-"
        print(f"  {fixture['case']:28} {action.verb:8} {action.severity:9} {fired}")
        report.append(
            {
                "case": fixture["case"],
                "input": fixture["output"],
                "verb": action.verb,
                "severity": action.severity,
                "output": action.output,
                "verdicts": action.verdicts,
                "metadata": action.metadata,
            }
        )
    path = write_report(report)
    print(f"\n  artifact written to {path}")
    return 0


if __name__ == "__main__":
    sys.exit(demo())

"""Unit tests for the output-side classifiers and the router."""

from __future__ import annotations

import unittest

from classifiers import (
    InstructionLeakageClassifier,
    PIIClassifier,
    ToxicityClassifier,
)
from main import Router


class TestToxicity(unittest.TestCase):
    def setUp(self) -> None:
        self.clf = ToxicityClassifier()

    def test_clean_text_is_none(self) -> None:
        v = self.clf.classify("That was a clear and helpful answer.")
        self.assertEqual(v.severity, "none")

    def test_single_term_low(self) -> None:
        v = self.clf.classify("You are a moron.")
        self.assertEqual(v.severity, "low")
        self.assertGreater(v.score, 0.0)

    def test_three_terms_high(self) -> None:
        v = self.clf.classify("You moron, you idiot, you worthless person.")
        self.assertEqual(v.severity, "high")

    def test_negation_window_skips(self) -> None:
        v = self.clf.classify("You are not stupid, that was a good idea.")
        self.assertEqual(v.severity, "none")

    def test_redact_replaces_term(self) -> None:
        out = self.clf.redact("You are a moron and a scumbag.")
        self.assertIn("[redacted-language]", out)
        self.assertNotIn("moron", out.lower())


class TestPII(unittest.TestCase):
    def setUp(self) -> None:
        self.clf = PIIClassifier()

    def test_email_is_medium(self) -> None:
        v = self.clf.classify("Reach us at hello@example.com soon.")
        self.assertEqual(v.severity, "medium")

    def test_valid_card_is_high(self) -> None:
        v = self.clf.classify("Card on file: 4111 1111 1111 1111.")
        self.assertEqual(v.severity, "high")

    def test_invalid_card_not_flagged(self) -> None:
        v = self.clf.classify("Random digits: 1234 5678 9012 3456.")
        self.assertNotIn("high", v.severity)

    def test_redact_email_and_card(self) -> None:
        out = self.clf.redact("Email me at jane@example.com or my card 4111 1111 1111 1111.")
        self.assertIn("[redacted-email]", out)
        self.assertIn("[redacted-card]", out)

    def test_ip_address_low(self) -> None:
        v = self.clf.classify("Server at 192.168.1.5 is up.")
        self.assertEqual(v.severity, "low")


class TestInstructionLeakage(unittest.TestCase):
    def test_leaks_system_prompt(self) -> None:
        sys_p = "You are PolicyBot. Refuse harmful requests. Cite sources."
        clf = InstructionLeakageClassifier(sys_p)
        v = clf.classify("As PolicyBot, I refuse harmful requests and I cite sources to the user.")
        self.assertIn(v.severity, {"low", "medium", "high"})

    def test_no_overlap_is_none(self) -> None:
        clf = InstructionLeakageClassifier("You are PolicyBot, follow internal policy.")
        v = clf.classify("Here is a pasta recipe with mushrooms and butter.")
        self.assertEqual(v.severity, "none")


class TestRouterDecisions(unittest.TestCase):
    def setUp(self) -> None:
        self.router = Router()

    def test_clean_is_log(self) -> None:
        a = self.router.run("Here is your requested haiku about autumn.")
        self.assertEqual(a.verb, "log")

    def test_low_toxicity_is_warn(self) -> None:
        a = self.router.run("You moron, your code is full of bugs.")
        self.assertEqual(a.verb, "warn")
        self.assertIn("[note", a.output)

    def test_email_is_redact(self) -> None:
        a = self.router.run("Reach me at lee@example.com tomorrow.")
        self.assertEqual(a.verb, "redact")
        self.assertIn("[redacted-email]", a.output)

    def test_card_is_block(self) -> None:
        a = self.router.run("Your card on file is 4111 1111 1111 1111.")
        self.assertEqual(a.verb, "block")
        self.assertNotIn("4111", a.output)


class TestRouterAggregation(unittest.TestCase):
    def test_block_dominates_redact(self) -> None:
        text = "Card 4111 1111 1111 1111. Also email a@b.com. Also you are a moron."
        a = Router().run(text)
        self.assertEqual(a.verb, "block")

    def test_metadata_lists_fired(self) -> None:
        text = "lee@example.com is great."
        a = Router().run(text)
        self.assertIn("pii", a.metadata["fired"])


if __name__ == "__main__":
    unittest.main()
